instruction:
COG maintains a project changing session for AI agents by using an envelope JSON
file and patch JSON file.

The envelope JSON file contains an instruction, a list of commands, and a list
of files produced by those commands.

Envelope format:

{
  "instruction": "...",
  "commands": [
    { "command": "read", "path": "path/to/file", "lines": 500, "sizeKB": 20 }
  ],
  "files": [
    {
      "path": "path/to/file",
      "type": "text",
      "content": "...",
      "complete": true
    },
    {
      "path": "path/to/binary",
      "type": "binary"
    }
  ]
}

A patch is a JSON file containing a task and a list of commands.

Patch format:
{
  "task": "...",
  "commands": [
    { "command": "read": "path": "path/to/file", "lines": 100, "sizeKB": 20 },
    { "command": "write": "path": "path/to/file", "content": "..." },
    { "command": "remove": "path": "path/to/file" }
  ]
}

Available patch commands:
- read: reads a file and adds it to the envelope.
- write: creates a file or sets the content of a file.
- remove: removes a file.

Workflow:
- The AI agent task is to provide a patch, either as a downloadable link to a file, or as a JSON object in a fenced JSON code block.
- Run `cog read <path> [<path> ...]` to read files into the envelope.
- Run `cog apply-patch` to apply the patch to the project files and update the envelope.

files.content:
import { loadEnvelope,
         saveEnvelope }
  from './model/envelope.js';
import { loadPatch }
  from './model/patch.js';
import { Read, read }
  from './commands/read.js';
import { Write, write }
  from './commands/write.js';
import { Remove, remove }
  from './commands/remove.js';

const envelopePath =
  getRequiredEnv("COG_ENVELOPE_PATH");

const patchPath =
  getRequiredEnv("COG_PATCH_PATH");

async function main(
  ): Promise<void>
{
  const [command, ...args] =
    process.argv.slice(2);

  if (command === 'read') {
    await readCmd(args);
    return;
  }

  if (command === 'apply-patch') {
    await applyPatch();
    return;
  }

  throw new Error(
    'Usage: cog <read|apply-patch> [args...]');
}

export async function readCmd(
    args: string[]
  ): Promise<void>
{
  if (args.length === 0) {
    throw new Error(
      'Usage: cog read <path> [<path> ...]');
  }

  const envelope =
    await loadEnvelope(
      envelopePath);

  for (const filePath of args) {
    await read(
      envelope,
      { command: 'read',
        path: filePath });
  }

  await saveEnvelope(
    envelope,
    envelopePath);
}

export async function applyPatch(
  ): Promise<void>
{
  const envelope =
    await loadEnvelope(
      envelopePath);

  const patch =
    await loadPatch(
      patchPath);

  for (const command of patch.commands) {
    if (command.command === "read") {
      await read(
        envelope,
        command as unknown as Read);
    } else if (command.command === "write") {
      await write(
        envelope,
        command as unknown as Write);
    } else if (command.command === "remove") {
      await remove(
        envelope,
        command as unknown as Remove);
    } else {
      throw new Error(
        `Unknown patch command ${command.command}`);
    }
  }

  await saveEnvelope(
    envelope,
    envelopePath);
}

export function getRequiredEnv(
    name: string
  ): string
{
  const value =
    process.env[name];

  if (!value) {
    throw new Error(
      `${name} is required`);
  }

  return value;
}

main()
  .catch(
    error => {
      console.error(
        error instanceof Error
          ? error.message
          : String(error));

      process.exitCode = 1;
    });
